router.post('/login', async (req, res) => {
  const { username, password } = req.body;
  const user = db.queryOne(
    'SELECT * FROM users WHERE username = ?', [username]);
  if (!user) return res.status(401).json(
    { error: '用户名或密码错误' });
  const valid = await bcrypt.compare(password, user.password);
  if (!valid) return res.status(401).json(
    { error: '用户名或密码错误' });
  const token = jwt.sign(
    { id: user.id, username: user.username, role: user.role },
    JWT_SECRET, { expiresIn: '7d' });
  res.json({ token, user: { id: user.id,
    username: user.username, role: user.role } });
});

function toggle3D() {
  is3D.value = !is3D.value;
  if (!map) return;
  if (is3D.value) {
    map.easeTo({ pitch: 60, bearing: -20,
      duration: 800 });
  } else {
    map.easeTo({ pitch: 0, bearing: 0,
      duration: 800 });
  }
}

async function planRoute(start: LngLat, end: LngLat) {
  const buildings = await loadBuildings();
  const vg = new VisibilityGraph(buildings);
  const path = vg.findPath(start, end);
  if (!path || path.length === 0) {
    return dijkstraFallback(start, end);
  }
  const dist = calcTotalDistance(path);
  const time = Math.ceil(dist / 80);
  return { path, distance: dist, duration: time };
}

router.get('/stats', adminMiddleware, (req, res) => {
  const totalUsers = db.queryOne(
    'SELECT COUNT(*) as c FROM users').c;
  const totalPOIs = db.queryOne(
    'SELECT COUNT(*) as c FROM pois').c;
  const totalNav = db.queryOne(
    'SELECT COUNT(*) as c FROM nav_logs').c;
  const navTrend = db.queryAll(
    'SELECT DATE(created_at) as date, COUNT(*) as count ' +
    'FROM nav_logs WHERE created_at >= ' +
    'DATE("now", "-7 days") GROUP BY date ORDER BY date');
  res.json({ totalUsers, totalPOIs, totalNav, navTrend });
});
